// Merge lodging guides + extra recommendations into each city catalog.
for (const cid of Object.keys(CITIES)) {
  const city = CITIES[cid];
  const extras = EXTRA_ITEMS_BY_CITY[cid] || [];
  const lodging = LODGING_BY_CITY[cid];
  const have = new Set((city.items || []).map((it) => it.id));
  if (lodging && !have.has(lodging.id)) city.items = [...(city.items || []), lodging];
  extras.forEach((it) => { if (!have.has(it.id)) { city.items.push(it); have.add(it.id); } });
  (city.items || []).forEach((it) => {
    if (it.heatSensitive && !it.heatReason && HEAT_REASON_DEFAULTS[it.id]) {
      it.heatReason = HEAT_REASON_DEFAULTS[it.id];
    }
  });
}

// City ids in the default-route order, for "all selectable cities" lists.
export const ROUTE_CITY_IDS = DEFAULT_ROUTE.map((s) => s.city);

// Convenience: every catalog city, default-route cities first, then extras.
export const ALL_CITY_IDS = [...ROUTE_CITY_IDS, ...EXTRA_CITY_IDS];

// Flat list of every catalog item, tagged with its city (for autocomplete +
// enrichment). Each entry keeps its original catalog id under both `id` and
// `sourceId` so it can be matched back to saved trip items.
export const ALL_CATALOG_ITEMS = ALL_CITY_IDS.flatMap((cid) =>
  (CITIES[cid].items || []).map((it) => ({ ...it, sourceId: it.id, cityId: cid, cityName: CITIES[cid].name })));

// "Deep bench" of extra lower-tier picks per city. Deliberately kept OUT of
// CITIES[].items (so they never auto-load into a stop's rec list), but offered
// by the city-scoped "Add a place" autocomplete and resolvable for enrichment.
export const SUGGESTION_ITEMS = ALL_CITY_IDS.flatMap((cid) =>
  (MORE_SUGGESTIONS_BY_CITY[cid] || []).map((it) => ({ ...it, sourceId: it.id, cityId: cid, cityName: CITIES[cid].name })));

// id -> catalog item, for backfilling enriched fields onto older saved trips.
// Includes the deep-bench items so any that get added to a trip still enrich.
export const CATALOG_ITEM_INDEX = [...ALL_CATALOG_ITEMS, ...SUGGESTION_ITEMS].reduce((acc, it) => {
  acc[it.id] = it;
  return acc;
}, {});
